import { CCol, CForm, CButton } from "@coreui/react";
import React, { useEffect, useState } from "react";
import Editor from "src/views/pages/editor/Editor";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import { v4 as uuidv4 } from 'uuid';
import authService from "src/auth/auth.service";

const blogCreateEditor = () => {

    let { pageId } = useParams();
    const navigate = useNavigate();
    const location = useLocation();

    const handleSubmit = () => {
        navigate("/blog");
    }

    const clickOnPrevios = () => {
        navigate(location?.state?.isUpdateBlogPage ? `/blog/edit/${pageId}` : `/blog/create`, { state: { backFromEditor: true, blogPageId: pageId }})
    }

    useEffect(() => {
        if(location?.state?.isUpdateBlogPage === undefined) {
            navigate(`/blog`);
        }
    })

    return (
        <div>
            <CForm className="row g-3 needs-validation" onSubmit={(e) => e.preventDefault()}>
                <CCol md={12}>
                    <Editor pageId={pageId} />
                </CCol>
                <CCol md={12}>
                    {authService.getPermission("BLOG_PUBLISH") && 
                        <CButton type="button" onClick={handleSubmit} color="primary" style={{ float: "right" }}>
                            {"Submit"}
                        </CButton>
                    }
                    <CButton type="button" onClick={clickOnPrevios} color="primary" style={{ float: "right", marginRight: "10px" }}>
                        {"Prev"}
                    </CButton>
                </CCol>
            </CForm>
        </div>
    );
};

export default blogCreateEditor;
